import { initSpotterI18n, useSptTranslation, sptI18n } from '@spotter/i18n-sdk';
import { SpotterMainApp } from '../type';
import { i18nInitProps } from '@spotter/i18n-sdk/lib/const';
export interface I18nSystemOptions extends i18nInitProps {}
export async function boostrapI18nSystem(options: I18nSystemOptions, sptApp: SpotterMainApp) {
    await initSpotterI18n(options)
        .then((i18n) => {
            console.log('i18n init success', i18n);
            sptApp.i18n = i18n;
            window.__SPOTTER_I18N_DATA__ = {
                useSptTranslation,
                sptI18n,
                i18n: i18n
            };
        })
        .catch((err) => {
            console.error('i18n init error', err);
        });
}
